#[derive(rkyv::Archive, rkyv::Serialize, rkyv::Deserialize, Clone, Debug, PartialEq, Eq)]
pub struct MessageSent {
    pub identifier: MessageIdentifier,
    pub origin_route: OriginRoute,
    pub root: MessageRoot,
    pub short_header: Integer,
}

#[derive(rkyv::Archive, rkyv::Serialize, rkyv::Deserialize, Clone, Debug, PartialEq, Eq)]
pub struct NexusMail<Payload> {
    pub identifier: MessageIdentifier,
    pub origin_route: OriginRoute,
    pub payload: Payload,
}

#[derive(rkyv::Archive, rkyv::Serialize, rkyv::Deserialize, Clone, Debug, PartialEq, Eq)]
pub struct MessageProcessed<Reply> {
    pub identifier: MessageIdentifier,
    pub origin_route: OriginRoute,
    pub reply: Reply,
}

pub trait MessageSentHook {
    type Error;

    fn message_sent(&mut self, event: MessageSent) -> Result<(), Self::Error>;
}

pub trait MessageProcessedHook<Reply> {
    type Error;

    fn message_processed(&mut self, event: MessageProcessed<Reply>) -> Result<(), Self::Error>;
}

impl MessageSent {
    pub fn origin_route(&self) -> OriginRoute {
        self.origin_route
    }

    pub fn push_to<Hook>(&self, hook: &mut Hook) -> Result<(), Hook::Error>
    where
        Hook: MessageSentHook,
    {
        hook.message_sent(self.clone())
    }
}

impl<Payload> NexusMail<Payload> {
    pub fn new(identifier: MessageIdentifier, origin_route: OriginRoute, payload: Payload) -> Self {
        Self { identifier, origin_route, payload }
    }

    pub fn identifier(&self) -> MessageIdentifier {
        self.identifier
    }

    pub fn origin_route(&self) -> OriginRoute {
        self.origin_route
    }

    pub fn into_payload(self) -> Payload {
        self.payload
    }
}

impl<Reply> MessageProcessed<Reply> {
    pub fn new(identifier: MessageIdentifier, origin_route: OriginRoute, reply: Reply) -> Self {
        Self { identifier, origin_route, reply }
    }

    pub fn identifier(&self) -> MessageIdentifier {
        self.identifier
    }

    pub fn origin_route(&self) -> OriginRoute {
        self.origin_route
    }

    pub fn into_reply(self) -> Reply {
        self.reply
    }

    pub fn push_to<Hook>(&self, hook: &mut Hook) -> Result<(), Hook::Error>
    where
        Hook: MessageProcessedHook<Reply>,
        Reply: Clone,
    {
        hook.message_processed(self.clone())
    }
}

impl Input {
    pub fn with_origin_route(self, origin_route: OriginRoute) -> Signal<Self> {
        Signal::new(origin_route, self)
    }

}

impl signal::Signal<Input> {
    pub fn message_sent(&self, identifier: MessageIdentifier) -> MessageSent {
        MessageSent {
            identifier,
            origin_route: self.origin_route(),
            root: MessageRoot::Input,
            short_header: self.root().short_header(),
        }
    }
}

impl Output {
    pub fn with_origin_route(self, origin_route: OriginRoute) -> Signal<Self> {
        Signal::new(origin_route, self)
    }

}

impl signal::Signal<Output> {
    pub fn message_sent(&self, identifier: MessageIdentifier) -> MessageSent {
        MessageSent {
            identifier,
            origin_route: self.origin_route(),
            root: MessageRoot::Output,
            short_header: self.root().short_header(),
        }
    }
}

pub mod signal {
    pub type Input = super::Input;
    pub type Output = super::Output;
    pub type Signal<Root> = super::Signal<Root>;
}

impl OriginRoute {
    pub fn from_nota_block(block: &nota_next::Block) -> Result<Self, NotaDecodeError> {
        Ok(Self(NotaBlock::new(block).parse_integer()?))
    }

    pub fn to_nota(self) -> String {
        self.0.to_string()
    }
}

pub trait InputNexus {
    type Reply;
    type Error;

    fn record(&self, mail: NexusMail<Entry>) -> Result<Self::Reply, Self::Error>;
    fn observe(&self, mail: NexusMail<Query>) -> Result<Self::Reply, Self::Error>;
    fn mark(&self, mail: NexusMail<DatabaseMarker>) -> Result<Self::Reply, Self::Error>;
    fn commit(&self, mail: NexusMail<CommitSequence>) -> Result<Self::Reply, Self::Error>;
}

impl Input {
    pub fn dispatch_mail_with_nexus<NexusActor>(self, identifier: MessageIdentifier, origin_route: OriginRoute, nexus: &NexusActor) -> Result<MessageProcessed<NexusActor::Reply>, NexusActor::Error>
    where
        NexusActor: InputNexus,
    {
        let reply = match self {
            Self::Record(payload) => nexus.record(NexusMail::new(identifier, origin_route, payload)),
            Self::Observe(payload) => nexus.observe(NexusMail::new(identifier, origin_route, payload)),
            Self::Mark(payload) => nexus.mark(NexusMail::new(identifier, origin_route, payload)),
            Self::Commit(payload) => nexus.commit(NexusMail::new(identifier, origin_route, payload)),
        }?;
        Ok(MessageProcessed::new(identifier, origin_route, reply))
    }
}

pub trait OutputNexus {
    type Reply;
    type Error;

    fn recorded(&self, mail: NexusMail<RecordReceipt>) -> Result<Self::Reply, Self::Error>;
    fn observed(&self, mail: NexusMail<RecordSet>) -> Result<Self::Reply, Self::Error>;
    fn marked(&self, mail: NexusMail<DatabaseMarker>) -> Result<Self::Reply, Self::Error>;
    fn committed(&self, mail: NexusMail<CommitSequence>) -> Result<Self::Reply, Self::Error>;
    fn rejected(&self, mail: NexusMail<Rejection>) -> Result<Self::Reply, Self::Error>;
}

impl Output {
    pub fn dispatch_mail_with_nexus<NexusActor>(self, identifier: MessageIdentifier, origin_route: OriginRoute, nexus: &NexusActor) -> Result<MessageProcessed<NexusActor::Reply>, NexusActor::Error>
    where
        NexusActor: OutputNexus,
    {
        let reply = match self {
            Self::Recorded(payload) => nexus.recorded(NexusMail::new(identifier, origin_route, payload)),
            Self::Observed(payload) => nexus.observed(NexusMail::new(identifier, origin_route, payload)),
            Self::Marked(payload) => nexus.marked(NexusMail::new(identifier, origin_route, payload)),
            Self::Committed(payload) => nexus.committed(NexusMail::new(identifier, origin_route, payload)),
            Self::Rejected(payload) => nexus.rejected(NexusMail::new(identifier, origin_route, payload)),
        }?;
        Ok(MessageProcessed::new(identifier, origin_route, reply))
    }
}

pub trait UpgradeFrom<Previous>: Sized {
    type Error;

    fn upgrade_from(previous: Previous) -> Result<Self, Self::Error>;
}

pub trait AcceptPrevious<Previous>: UpgradeFrom<Previous> {
    fn accept_previous(previous: Previous) -> Result<Self, Self::Error> {
        Self::upgrade_from(previous)
    }
}

impl<Current, Previous> AcceptPrevious<Previous> for Current where Current: UpgradeFrom<Previous> {}
